import{c as t,S as d,j as a,m as r}from"./chunks/framework.DvQr6YbT.js";const p=JSON.parse('{"title":"Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/index.md","filePath":"reference/index.md","lastUpdated":1783505267000}'),o={name:"reference/index.md"};function n(i,e,s,l,c,h){return d(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to “Reference”">​</a></h1><p>This reference lists the files, commands, skills, and safety boundaries used by Knowlery.</p><h2 id="plugin-metadata" tabindex="-1">Plugin Metadata <a class="header-anchor" href="#plugin-metadata" aria-label="Permalink to “Plugin Metadata”">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Current value</th></tr></thead><tbody><tr><td>Plugin ID</td><td><code>knowlery</code></td></tr><tr><td>Minimum Obsidian app version</td><td><code>1.12.2</code></td></tr><tr><td>Desktop-only manifest flag</td><td><code>true</code></td></tr><tr><td>Main bundle</td><td><code>main.js</code></td></tr><tr><td>Stylesheet</td><td><code>styles.css</code></td></tr></tbody></table><h2 id="dashboard-and-settings-surfaces" tabindex="-1">Dashboard and Settings Surfaces <a class="header-anchor" href="#dashboard-and-settings-surfaces" aria-label="Permalink to “Dashboard and Settings Surfaces”">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>Purpose</th></tr></thead><tbody><tr><td>Dashboard home</td><td>Today&#39;s move, suggested moves, Knowledge health, This note, Recent activity, This week, and Bundles</td></tr><tr><td>Share knowledge bundle</td><td>Seed picking, graph-closure review, risk scan, and bundle export</td></tr><tr><td>Install knowledge bundle</td><td>Manifest and conformance preview, install, and installed-bundle list</td></tr><tr><td>Move drill-ins</td><td>Full suggested-move list and individual move prompts</td></tr><tr><td>Activity drill-in</td><td>Full recent activity list</td></tr><tr><td>Freshness Review</td><td>Request preparation, result import, suggestion decisions, apply, and undo</td></tr><tr><td>Settings: Diagnostics</td><td>Vault health, content stats, configuration integrity, and diagnosis</td></tr><tr><td>Settings: Rules &amp; schema</td><td>Agent rules, schema shortcuts, and config maintenance</td></tr><tr><td>Settings: Skills</td><td>Built-in, registry, custom, and disabled skill management</td></tr></tbody></table><h2 id="created-files-and-folders" tabindex="-1">Created Files and Folders <a class="header-anchor" href="#created-files-and-folders" aria-label="Permalink to “Created Files and Folders”">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Created by</th><th>Notes</th></tr></thead><tbody><tr><td><code>KNOWLEDGE.md</code></td><td>Setup</td><td>Vault operating guide</td></tr><tr><td><code>SCHEMA.md</code></td><td>Setup</td><td>Knowledge taxonomy and page conventions</td></tr><tr><td><code>INDEX.base</code></td><td>Setup</td><td>Bases index</td></tr><tr><td><code>entities/</code></td><td>Setup</td><td>Agent-maintained entity pages</td></tr><tr><td><code>concepts/</code></td><td>Setup</td><td>Agent-maintained concept pages</td></tr><tr><td><code>comparisons/</code></td><td>Setup</td><td>Agent-maintained comparison pages</td></tr><tr><td><code>queries/</code></td><td>Setup</td><td>Agent-maintained research threads</td></tr><tr><td><code>.knowlery/manifest.json</code></td><td>Setup</td><td>Setup state</td></tr><tr><td><code>.agents/skills/</code></td><td>Setup</td><td>Canonical skills</td></tr><tr><td><code>.agents/rules/</code></td><td>OpenCode</td><td>Rules for OpenCode</td></tr><tr><td><code>.claude/skills/</code></td><td>Setup</td><td>Mirrored built-in skills for Claude Code</td></tr><tr><td><code>.claude/CLAUDE.md</code></td><td>Claude Code</td><td>Claude instructions</td></tr><tr><td><code>.claude/rules/</code></td><td>Claude Code</td><td>Rules for Claude Code</td></tr><tr><td><code>opencode.json</code></td><td>OpenCode</td><td>OpenCode config</td></tr><tr><td><code>skills-lock.json</code></td><td>Setup</td><td>Skill lock state</td></tr><tr><td><code>.knowlery/activity/</code></td><td>Activity logging</td><td>Private activity receipts</td></tr><tr><td><code>.knowlery/reports/</code></td><td>Weekly summary</td><td>Local HTML report output</td></tr><tr><td><code>.knowlery/requests/</code></td><td>Daily polish</td><td>Daily review requests</td></tr><tr><td><code>.knowlery/reviews/</code></td><td>Daily polish</td><td>Daily review results</td></tr><tr><td><code>.knowlery/freshness/</code></td><td>Freshness Review</td><td>Request, result, log, queue, and sidecar files</td></tr><tr><td><code>.knowlery/exports/</code></td><td>Share knowledge bundle</td><td>Compiled bundle output (optionally zipped)</td></tr><tr><td><code>.knowlery/export-scope.json</code></td><td>Share knowledge bundle</td><td>Saved per-topic review scope</td></tr><tr><td><code>Library/&lt;bundle-id&gt;/</code></td><td>Install knowledge bundle</td><td>Installed bundle contents</td></tr><tr><td><code>.knowlery/bundles.json</code></td><td>Install knowledge bundle</td><td>Installed bundle registry</td></tr></tbody></table><h2 id="built-in-skills" tabindex="-1">Built-In Skills <a class="header-anchor" href="#built-in-skills" aria-label="Permalink to “Built-In Skills”">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Kind</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cook</code></td><td>knowledge</td><td>Digest notes into knowledge pages and keep <code>SCHEMA.md</code> aligned</td></tr><tr><td><code>ask</code></td><td>knowledge</td><td>Answer questions from vault content</td></tr><tr><td><code>explore</code></td><td>knowledge</td><td>Trace idea timelines and bridges</td></tr><tr><td><code>challenge</code></td><td>knowledge</td><td>Pressure-test beliefs and drift</td></tr><tr><td><code>ideas</code></td><td>knowledge</td><td>Generate ideas from vault content</td></tr><tr><td><code>audit</code></td><td>knowledge</td><td>Scan agent-maintained directories for structural health issues</td></tr><tr><td><code>organize</code></td><td>knowledge</td><td>Suggest structure improvements</td></tr><tr><td><code>obsidian-cli</code></td><td>tooling</td><td>Use Obsidian CLI patterns</td></tr><tr><td><code>obsidian-markdown</code></td><td>tooling</td><td>Write Obsidian markdown</td></tr><tr><td><code>obsidian-bases</code></td><td>tooling</td><td>Work with Bases files</td></tr><tr><td><code>json-canvas</code></td><td>tooling</td><td>Work with JSON Canvas</td></tr><tr><td><code>defuddle</code></td><td>tooling</td><td>Extract clean markdown from web pages</td></tr><tr><td><code>vault-conventions</code></td><td>tooling</td><td>Enforce vault naming conventions</td></tr><tr><td><code>knowlery-cli</code></td><td>tooling</td><td>Operate the knowledge base with the standalone <code>knowlery</code> CLI</td></tr></tbody></table><h2 id="settings-sections" tabindex="-1">Settings Sections <a class="header-anchor" href="#settings-sections" aria-label="Permalink to “Settings Sections”">​</a></h2><table tabindex="0"><thead><tr><th>Section</th><th>What it controls</th></tr></thead><tbody><tr><td>General</td><td>Knowledge base name and Node.js path</td></tr><tr><td>Platform</td><td>Claude Code / OpenCode switching</td></tr><tr><td>Activity</td><td>Activity logging and activity ledger rule</td></tr><tr><td>Maintenance</td><td>Regenerate agent config and re-initialize vault</td></tr></tbody></table><h2 id="default-rule-templates" tabindex="-1">Default Rule Templates <a class="header-anchor" href="#default-rule-templates" aria-label="Permalink to “Default Rule Templates”">​</a></h2><p>Knowlery includes default rule templates for:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Purpose</th></tr></thead><tbody><tr><td>Citation required</td><td>Require wikilink citations for vault answers</td></tr><tr><td>Language preference</td><td>Match the user&#39;s language</td></tr><tr><td>Domain context</td><td>Describe the vault&#39;s domain</td></tr></tbody></table><h2 id="commands-registered-in-obsidian" tabindex="-1">Commands Registered in Obsidian <a class="header-anchor" href="#commands-registered-in-obsidian" aria-label="Permalink to “Commands Registered in Obsidian”">​</a></h2><p>Knowlery registers command palette actions for:</p><ul><li>Opening the dashboard.</li><li>Initializing the vault.</li><li>Running vault diagnosis.</li><li>Adding a reflection.</li><li>Sharing a knowledge bundle.</li><li>Installing a knowledge bundle.</li><li>Switching platforms.</li></ul><p>The exact labels may evolve with the plugin UI, but the command surface is centered on review, setup, diagnosis, and platform migration.</p><h2 id="activity-ledger" tabindex="-1">Activity Ledger <a class="header-anchor" href="#activity-ledger" aria-label="Permalink to “Activity Ledger”">​</a></h2><p>Activity receipts live in <code>.knowlery/activity/YYYY-MM-DD.jsonl</code>.</p><p>They are private summaries, not normal knowledge pages. The activity toggle in settings can disable logging by writing <code>.knowlery/activity-disabled</code>.</p><h2 id="weekly-summary-and-daily-review" tabindex="-1">Weekly Summary and Daily Review <a class="header-anchor" href="#weekly-summary-and-daily-review" aria-label="Permalink to “Weekly Summary and Daily Review”">​</a></h2><p>The weekly summary writes HTML output to:</p><ul><li><code>.knowlery/reports/latest.html</code></li><li><code>.knowlery/reports/weekly/&lt;week-label&gt;.html</code></li></ul><p>Daily review polish uses:</p><ul><li><code>.knowlery/requests/daily-review-YYYY-MM-DD.json</code></li><li><code>.knowlery/reviews/daily-review-YYYY-MM-DD.json</code></li></ul><h2 id="freshness-review-files" tabindex="-1">Freshness Review Files <a class="header-anchor" href="#freshness-review-files" aria-label="Permalink to “Freshness Review Files”">​</a></h2><p>Freshness Review uses:</p><ul><li><code>.knowlery/freshness/requests/freshness-review-&lt;timestamp&gt;.json</code></li><li><code>.knowlery/freshness/results/freshness-review-&lt;timestamp&gt;.json</code></li><li><code>.knowlery/freshness/logs/freshness-review-&lt;timestamp&gt;.jsonl</code></li><li><code>.knowlery/freshness/queue.json</code></li><li><code>.knowlery/freshness/notes/*.json</code></li></ul><p>Candidate pages are collected from <code>entities/</code>, <code>concepts/</code>, <code>comparisons/</code>, and <code>queries/</code>, capped by the current candidate limit. Suggestions can only patch scalar freshness frontmatter on those knowledge pages.</p><h2 id="network-use" tabindex="-1">Network Use <a class="header-anchor" href="#network-use" aria-label="Permalink to “Network Use”">​</a></h2><p>Knowlery does not collect telemetry.</p><p>Network access can happen when you explicitly use skill registry features through <code>npx skills ...</code>. That command may contact services used by the external skills tooling. Freshness Review does not call a model API; it prepares local request files and imports result files written by an agent you run separately.</p><h2 id="local-command-use" tabindex="-1">Local Command Use <a class="header-anchor" href="#local-command-use" aria-label="Permalink to “Local Command Use”">​</a></h2><p>Knowlery can run local commands when you explicitly use CLI-related features or optional setup preparation.</p><p>Examples include:</p><ul><li><code>claude</code></li><li><code>opencode</code></li><li><code>node</code></li><li><code>npx</code></li><li><code>skills</code></li></ul><p>These commands run on your computer with your user permissions.</p><h2 id="upgrade-behavior" tabindex="-1">Upgrade Behavior <a class="header-anchor" href="#upgrade-behavior" aria-label="Permalink to “Upgrade Behavior”">​</a></h2><p>When the plugin version changes, Knowlery refreshes bundled skills in <code>.agents/skills/</code> and <code>.claude/skills/</code>, migrates <code>SCHEMA.md</code> by inserting any missing anchor sections, and refreshes the installed-bundles pointer block in <code>KNOWLEDGE.md</code> when bundles are installed.</p><p>In v0.5.0, knowledge bundle sharing and installing arrived: the Bundles section on the dashboard, the <code>Library/</code> folder, and <code>.knowlery/bundles.json</code> are new surfaces. In v0.4.0, dashboard maintenance moved into Obsidian settings: diagnostics, rules and schema shortcuts, and the Skills library are no longer separate dashboard tabs.</p><p>Custom and forked skills are preserved. Disabled built-in skills keep their disabled state, even though the on-disk bundled copy is refreshed.</p><h2 id="deletion-behavior" tabindex="-1">Deletion Behavior <a class="header-anchor" href="#deletion-behavior" aria-label="Permalink to “Deletion Behavior”">​</a></h2><p>Knowlery may remove skill or rule files when you use delete or disable actions in the UI.</p><p>It should not delete ordinary user notes during setup. Still, test first and use version control or backups for important vaults.</p>',46)])])}const g=t(o,[["render",n]]);export{p as __pageData,g as default};
